import UIKit
import CryptoKit

class WalletViewController: UIViewController {
    var privateKey: Data?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        generatePrivateKey()
    }
    
    func generatePrivateKey() {
        privateKey = Curve25519.Signing.generateKeyPair().privateKey.rawRepresentation
        print("Private Key: \(privateKey?.hexString ?? "")")
    }
    
    func signTransaction(transactionData: Data) -> Data? {
        guard let privateKey = privateKey else { return nil }
        
        do {
            let signature = try Curve25519.Signing.sign(message: transactionData, using: privateKey)
            return signature.rawRepresentation
        } catch {
            print("Error signing transaction: \(error)")
            return nil
        }
    }
}

extension Data {
    var hexString: String {
        return map { String(format: "%02hhx", $0) }.joined()
    }
